                        <div className="tecnicos-selecionados-scroll">
                            {tecnicosSelecionados.length === 0 ? (
                                <div className="empty-placeholder-selected">
                                    <i className="fas fa-user-plus"></i> Selecione técnicos ao lado
                                </div>
                            ) : (
                                Object.entries(tecnicosSelecionadosAgrupados).map(([regional, tecnicos]) => (
                                    <div key={regional} className="regional-selecionada">
                                        <div className="regional-titulo-selecionada">
                                            <i className="fas fa-map-marker-alt"></i>
                                            <span>{regional}</span>
                                            <span className="contador">{tecnicos.length}</span>
                                        </div>
                                        <div className="tecnicos-selecionados-lista">
                                            {tecnicos.map((tec) => (
                                                <div key={tec.nome} className="tecnico-selecionado-item">
                                                    <div className="tecnico-selecionado-header">
                                                        <i className="fas fa-user"></i>
                                                        <span className="tecnico-selecionado-nome">{tec.nome}</span>
                                                        <button
                                                            className="btn-remove-tecnico"
                                                            onClick={() => toggleTecnico(tec)}
                                                        >
                                                            <i className="fas fa-times-circle"></i>
                                                        </button>
                                                    </div>
                                                    <div className="tecnico-selecionado-config">
                                                        <div className="radio-group-tipo-tecnico">
                                                            {TIPOS_TECNICO.map((tipo) => (
                                                                <label
                                                                    key={tipo}
                                                                    className={`radio-tipo ${
                                                                        tec.tipoTecnico === tipo ? "active" : ""
                                                                    }`}
                                                                    onClick={() => atualizarTipoTecnico(tec, tipo)}
                                                                >
                                                                    <input
                                                                        type="radio"
                                                                        name={`tipo-${tec.nome}`}
                                                                        checked={tec.tipoTecnico === tipo}
                                                                        onChange={() => {}}
                                                                    />
                                                                    <span>{tipo}</span>
                                                                </label>
                                                            ))}
                                                        </div>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                        <div className="card-footer-actions" style={{display: "flex", gap: "0.5rem", flexWrap: "wrap"}}>
                            <button
                                onClick={() => configurarPadraoParaSelecionados("12/36")}
                                className="btn-outline-primary"
                                style={{flex: 1}}
                            >
                                <i className="fas fa-clock"></i> 12/36
                            </button>
                            <button
                                onClick={() => configurarPadraoParaSelecionados("Comercial")}
                                className="btn-outline-primary"
                                style={{flex: 1}}
                            >
                                <i className="fas fa-briefcase"></i> Comercial
                            </button>
                        </div>
                        <div className="card-footer-actions" style={{marginTop: "0.5rem"}}>
                            <button
                                onClick={processarProdutividade}
                                className="btn-processar"
                                disabled={carregando || tecnicosSelecionados.length === 0}
                            >
                                <i className="fas fa-chart-simple"></i>
                                {carregando ? "Processando..." : "Processar Produtividade"}
                            </button>
                        </div>
                    </div>
                </div>
            </div>

            {/* Resultados */}
            {dadosProdutividade.length > 0 && (
                <>
                    {/* Filtros */}
                    <div style={{display: "flex", gap: "1rem", flexWrap: "wrap", marginBottom: "1.5rem"}}>
                        <div className="filtro-acionamento-container" style={{flex: 1}}>
                            <label>
                                <i className="fas fa-filter"></i> Filtrar por tipo de técnico:
                            </label>
                            <div className="filtro-acionamento-buttons">
                                <button
                                    className={`filtro-btn ${filtroTipoTecnico === "todos" ? "active" : ""}`}
                                    onClick={() => setFiltroTipoTecnico("todos")}
                                >
                                    Todos ({dadosProdutividade.length})
                                </button>
                                {TIPOS_TECNICO.map((tipo) => (
                                    <button
                                        key={tipo}
                                        className={`filtro-btn ${filtroTipoTecnico === tipo ? "active" : ""}`}
                                        onClick={() => setFiltroTipoTecnico(tipo)}
                                    >
                                        {tipo} ({dadosProdutividade.filter((i) => i.tipoTecnico === tipo).length})
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div style={{background: "white", borderRadius: "16px", padding: "1rem", flex: 1}}>
                            <label>
                                <i className="fas fa-tasks"></i> Filtrar por tipo de protocolo:
                            </label>
                            <div style={{display: "flex", gap: "0.5rem", marginTop: "0.5rem", flexWrap: "wrap"}}>
                                <button
                                    className={`filtro-btn ${filtroTipoProtocolo === "todos" ? "active" : ""}`}
                                    onClick={() => {
                                        setFiltroTipoProtocolo("todos");
                                        setTimeout(
                                            () =>
                                                atualizarGraficos(
                                                    dadosProdutividade,
                                                    metricasAgregadas,
                                                    metricasPorRegional
                                                ),
                                            100
                                        );
                                    }}
                                >
                                    Todos os protocolos
                                </button>
                                <button
                                    className={`filtro-btn ${filtroTipoProtocolo === "normal" ? "active" : ""}`}
                                    onClick={() => {
                                        setFiltroTipoProtocolo("normal");
                                        setTimeout(
                                            () =>
                                                atualizarGraficos(
                                                    dadosProdutividade,
                                                    metricasAgregadas,
                                                    metricasPorRegional
                                                ),
                                            100
                                        );
                                    }}
                                >
                                    <i className="fas fa-chart-line"></i> NORMAL
                                </button>
                                <button
                                    className={`filtro-btn ${filtroTipoProtocolo === "acionamento" ? "active" : ""}`}
                                    onClick={() => {
                                        setFiltroTipoProtocolo("acionamento");
                                        setTimeout(
                                            () =>
                                                atualizarGraficos(
                                                    dadosProdutividade,
                                                    metricasAgregadas,
                                                    metricasPorRegional
                                                ),
                                            100
                                        );
                                    }}
                                >
                                    <i className="fas fa-bolt"></i> Acionamento (AC)
                                </button>
                                <button
                                    className={`filtro-btn ${filtroTipoProtocolo === "ativacao" ? "active" : ""}`}
                                    onClick={() => {
                                        setFiltroTipoProtocolo("ativacao");
                                        setTimeout(
                                            () =>
                                                atualizarGraficos(
                                                    dadosProdutividade,
                                                    metricasAgregadas,
                                                    metricasPorRegional
                                                ),
                                            100
                                        );
                                    }}
                                >
                                    <i className="fas fa-play-circle"></i> Ativação (AA)
                                </button>
                            </div>
                        </div>
                    </div>

                    {/* Abas de Detalhamento */}
                    <div
                        style={{
                            display: "flex",
                            gap: "1rem",
                            marginBottom: "1.5rem",
                            borderBottom: "1px solid #e2e8f0",
                        }}
                    >
                        <button
                            onClick={() => setAbaDetalhe("tecnicos")}
                            style={{
                                padding: "0.75rem 1.5rem",
                                background: "none",
                                border: "none",
                                borderBottom: abaDetalhe === "tecnicos" ? "3px solid #E8465D" : "3px solid transparent",
                                color: abaDetalhe === "tecnicos" ? "#E8465D" : "#64748b",
                                fontWeight: 600,
                                cursor: "pointer",
                                boxShadow: "none",
                                minWidth: "auto",
                            }}
                        >
                            <i className="fas fa-users"></i> Detalhamento por Técnico
                        </button>
                        <button
                            onClick={() => setAbaDetalhe("regionais")}
                            style={{
                                padding: "0.75rem 1.5rem",
                                background: "none",
                                border: "none",
                                borderBottom:
                                    abaDetalhe === "regionais" ? "3px solid #E8465D" : "3px solid transparent",
                                color: abaDetalhe === "regionais" ? "#E8465D" : "#64748b",
                                fontWeight: 600,
                                cursor: "pointer",
                                boxShadow: "none",
                                minWidth: "auto",
                            }}
                        >
                            <i className="fas fa-map-marker-alt"></i> Detalhamento por Regional
                        </button>
                    </div>

                    <div className="summary-cards-produtividade">
                        <div className="summary-card-prod">
                            <div className="card-icon-prod" style={{background: "#E8465D20"}}>
                                <i className="fas fa-tasks" style={{color: "#E8465D"}}></i>
                            </div>
                            <div className="card-info-prod">
                                <h3>{totalProtocolos}</h3>
                                <p>Total de Protocolos</p>
                            </div>
                        </div>
                        <div className="summary-card-prod">
                            <div className="card-icon-prod" style={{background: "#28a74520"}}>
                                <i className="fas fa-check-circle" style={{color: "#28a745"}}></i>
                            </div>
                            <div className="card-info-prod">
                                <h3>{metricasFiltradas.execucao}</h3>
                                <p>Protocolos Executados</p>
                            </div>
                        </div>
                        <div className="summary-card-prod">
                            <div className="card-icon-prod" style={{background: "#ffc10720"}}>
                                <i className="fas fa-chart-line" style={{color: "#ffc107"}}></i>
                            </div>
                            <div className="card-info-prod">
                                <h3>{metricasFiltradas.totalProdutividade.toFixed(2)}</h3>
                                <p>Produtividade Total</p>
                            </div>
                        </div>
                    </div>

                    {/* Gráficos */}
                    <div className="charts-grid-produtividade">
                        <div className="chart-card-prod">
                            <div className="chart-header-prod">
                                <i className="fas fa-chart-bar"></i>
                                <h4>Métricas por Tipo</h4>
                            </div>
                            <canvas ref={metricasChartRef} id="metricasGeraisChart" height="280"></canvas>
                        </div>
                        <div className="chart-card-prod">
                            <div className="chart-header-prod">
                                <i className="fas fa-chart-pie"></i>
                                <h4>Distribuição Percentual</h4>
                            </div>
                            <canvas ref={distribuicaoChartRef} id="distribuicaoChart" height="280"></canvas>
                        </div>
                        <div className="chart-card-prod">
                            <div className="chart-header-prod">
                                <i className="fas fa-chart-bar"></i>
                                <h4>Produtividade por Regional</h4>
                            </div>
                            <canvas ref={regionalChartRef} id="regionalChart" height="280"></canvas>
                        </div>
                        <div className="chart-card-prod chart-full-width">
                            <div className="chart-header-prod">
                                <i className="fas fa-trophy"></i>
                                <h4>Produtividade por Técnico</h4>
                            </div>
                            <canvas ref={tecnicosChartRef} id="produtividadeTecnicosChart" height="300"></canvas>
                        </div>
                    </div>

                    {/* Detalhamento por Técnico */}
                    {abaDetalhe === "tecnicos" && (
                        <div className="tabela-resultados-prod">
                            <div className="tabela-header">
                                <h4>
                                    <i className="fas fa-table"></i> Detalhamento por Técnico
                                </h4>
                                <button onClick={exportarResultados} className="btn-exportar">
                                    <i className="fas fa-file-excel"></i> Exportar CSV
                                </button>
                            </div>
                            <div className="table-responsive" style={{maxHeight: "500px", overflowY: "auto"}}>
                                <table className="data-table-prod" style={{width: "100%"}}>
                                    <thead style={{position: "sticky", top: 0, background: "white", zIndex: 10}}>
                                        <tr>
                                            <th>Técnico</th>
                                            <th>Regional</th>
                                            <th>Tipo Config.</th>
                                            <th>AC/AA</th>
                                            <th>Planej.</th>
                                            <th>Exec.</th>
                                            <th>Remarc.</th>
                                            <th>Cancel.</th>
                                            <th>Produtiv.</th>
                                            <th>Exec NORM</th>
                                            <th>Exec AC</th>
                                            <th>Exec AA</th>
                                            <th>Meta</th>
                                            <th>Status</th>
                                            <th>Ações</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {dadosFiltrados.map((item, idx) => {
                                            const execucaoNormal = item.normalExecucao || 0;
                                            const execucaoAcionamento = item.acionamentoExecucao || 0;
                                            const execucaoAtivacao = item.ativacaoExecucao || 0;
                                            let produtividadeExibida = item.produtividade;
                                            if (filtroTipoProtocolo === "normal")
                                                produtividadeExibida = item.normalProdutividade || 0;
                                            if (filtroTipoProtocolo === "acionamento")
                                                produtividadeExibida = item.acionamentoProdutividade || 0;
                                            if (filtroTipoProtocolo === "ativacao")
                                                produtividadeExibida = item.ativacaoProdutividade || 0;

                                            const temAcionamento = execucaoAcionamento > 0;
                                            const temAtivacao = execucaoAtivacao > 0;
                                            let badgeTipos = "";
                                            if (temAcionamento && temAtivacao)
                                                badgeTipos = '<span class="badge-tipo badge-ambos">AC+AA</span>';
                                            else if (temAcionamento)
                                                badgeTipos = '<span class="badge-tipo badge-acionamento">AC</span>';
                                            else if (temAtivacao)
                                                badgeTipos = '<span class="badge-tipo badge-ativacao">AA</span>';
                                            else badgeTipos = '<span class="badge-tipo badge-normal">-</span>';

                                            return (
                                                <tr
                                                    key={idx}
                                                    className={
                                                        item.tipoTecnico && !item.meta.atingiuProdutividade
                                                            ? "meta-abaixo"
                                                            : ""
                                                    }
                                                >
                                                    <td>
                                                        <strong>{item.tecnico}</strong>
                                                    </td>
                                                    <td>{item.regional}</td>
                                                    <td>
                                                        {item.tipoTecnico ? (
                                                            <span
                                                                className={`badge-tipo ${
                                                                    item.tipoTecnico === "12/36"
                                                                        ? "badge-1236"
                                                                        : "badge-comercial"
                                                                }`}
                                                            >
                                                                {item.tipoTecnico}
                                                            </span>
                                                        ) : (
                                                            <span className="badge-nao-config">Não config.</span>
                                                        )}
                                                    </td>
                                                    <td dangerouslySetInnerHTML={{__html: badgeTipos}} />
                                                    <td>{item.planejamento}</td>
                                                    <td>
                                                        <strong>{item.execucao}</strong>
                                                    </td>
                                                    <td>{item.remarcacao}</td>
                                                    <td>{item.cancelamento}</td>
                                                    <td className="produtividade-destaque">
                                                        {produtividadeExibida.toFixed(2)}
                                                    </td>
                                                    <td>{execucaoNormal}</td>
                                                    <td>{execucaoAcionamento}</td>
                                                    <td>{execucaoAtivacao}</td>
                                                    <td>
                                                        <small>
                                                            {item.meta.produtividadeMin
                                                                ? `${item.meta.produtividadeMin}pts / ${item.meta.protocolosMin}prot`
                                                                : "-"}
                                                        </small>
                                                    </td>
                                                    <td>
                                                        <span
                                                            className={`status-badge ${
                                                                item.tipoTecnico
                                                                    ? item.meta.atingiuProdutividade &&
                                                                      item.meta.atingiuProtocolos
                                                                        ? "status-success"
                                                                        : "status-warning"
                                                                    : "status-pending"
                                                            }`}
                                                        >
                                                            {item.meta.status}
                                                        </span>
                                                    </td>
                                                    <td>
                                                        <button
                                                            className="btn-detalhes"
                                                            onClick={() => verDetalhesTecnico(item)}
                                                        >
                                                            <i className="fas fa-eye"></i> Detalhes
                                                        </button>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                    <tfoot>
                                        <tr className="total-row">
                                            <td colSpan="4">
                                                <strong>TOTAIS</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.planejamento}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.execucao}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.remarcacao}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.cancelamento}</strong>
                                            </td>
                                            <td className="produtividade-destaque">
                                                <strong>{metricasFiltradas.totalProdutividade.toFixed(2)}</strong>
                                            </td>
                                            <td colSpan="5"></td>
                                        </tr>
                                    </tfoot>
                                </table>
                            </div>
                        </div>
                    )}

                    {/* Detalhamento por Regional */}
                    {abaDetalhe === "regionais" && dadosConsolidados?.regionais && (
                        <div className="tabela-resultados-prod">
                            <div className="tabela-header">
                                <h4>
                                    <i className="fas fa-table"></i> Detalhamento por Regional
                                </h4>
                                <button onClick={exportarResultados} className="btn-exportar">
                                    <i className="fas fa-file-excel"></i> Exportar CSV
                                </button>
                            </div>
                            <div className="table-responsive" style={{maxHeight: "500px", overflowY: "auto"}}>
                                <table className="data-table-prod" style={{width: "100%"}}>
                                    <thead style={{position: "sticky", top: 0, background: "white", zIndex: 10}}>
                                        <tr>
                                            <th>Regional</th>
                                            <th>Técnicos</th>
                                            <th>Planej.</th>
                                            <th>Exec.</th>
                                            <th>Remarc.</th>
                                            <th>Cancel.</th>
                                            <th>Produtividade</th>
                                            <th>Exec NORMAL</th>
                                            <th>Exec AC</th>
                                            <th>Exec AA</th>
                                            <th>Produtividade Média</th>
                                            <th>Ações</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {Object.entries(dadosConsolidados.regionais).map(([regional, dados]) => {
                                            const produtividadeMedia = dados.totalProdutividade / dados.tecnicos;
                                            const execucaoNormal = dados.normalExecucao || 0;
                                            const execucaoAcionamento = dados.acionamentoExecucao || 0;
                                            const execucaoAtivacao = dados.ativacaoExecucao || 0;
                                            let produtividadeExibida = dados.totalProdutividade;
                                            if (filtroTipoProtocolo === "normal")
                                                produtividadeExibida = dados.normalTotalProdutividade || 0;
                                            if (filtroTipoProtocolo === "acionamento")
                                                produtividadeExibida = dados.acionamentoTotalProdutividade || 0;
                                            if (filtroTipoProtocolo === "ativacao")
                                                produtividadeExibida = dados.ativacaoTotalProdutividade || 0;

                                            return (
                                                <tr key={regional}>
                                                    <td>
                                                        <strong>{regional}</strong>
                                                    </td>
                                                    <td>{dados.tecnicos}</td>
                                                    <td>{dados.planejamento}</td>
                                                    <td>
                                                        <strong>{dados.execucao}</strong>
                                                    </td>
                                                    <td>{dados.remarcacao}</td>
                                                    <td>{dados.cancelamento}</td>
                                                    <td className="produtividade-destaque">
                                                        {produtividadeExibida.toFixed(2)}
                                                    </td>
                                                    <td>{execucaoNormal}</td>
                                                    <td>{execucaoAcionamento}</td>
                                                    <td>{execucaoAtivacao}</td>
                                                    <td>{produtividadeMedia.toFixed(2)}</td>
                                                    <td>
                                                        <button
                                                            className="btn-detalhes"
                                                            onClick={() => verDetalhesRegional(regional, dados)}
                                                        >
                                                            <i className="fas fa-eye"></i> Detalhes
                                                        </button>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                    <tfoot>
                                        <tr className="total-row">
                                            <td>
                                                <strong>TOTAIS</strong>
                                            </td>
                                            <td>
                                                <strong>{Object.keys(dadosConsolidados.regionais).length}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.planejamento}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.execucao}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.remarcacao}</strong>
                                            </td>
                                            <td>
                                                <strong>{metricasFiltradas.cancelamento}</strong>
                                            </td>
                                            <td className="produtividade-destaque">
                                                <strong>{metricasFiltradas.totalProdutividade.toFixed(2)}</strong>
                                            </td>
                                            <td colSpan="5"></td>
                                        </tr>
                                    </tfoot>
                                </table>
                            </div>
                        </div>
                    )}
                </>
            )}
        </div>
    );
};

export default AbaProdutividade;
